import React, { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { addSensor, deleteSensor } from "../api/sensorsapi";
import { getActiveSensors } from "../api/activeapi";
import ConnectionModal from "../components/ConnectionModal";
import MqttForm from "../components/MqttForm";
import { updateConnection, deleteConnection, getConnections } from "../api/connectionsapi";
import api from "../api/axiosInstance";

const Sensor = () => {
  const navigate = useNavigate();
  const role    = localStorage.getItem("sb_role");
  const isAdmin = role === "admin";

  const [connections, setConnections]           = useState([]);
  const [activeConnectionId, setActiveConnectionId] = useState(null);
  const [sensors, setSensors]                   = useState([]);
  const [showForm, setShowForm]                 = useState(false);
  const [showConnectionModal, setShowConnectionModal] = useState(false);
  const [successMsg, setSuccessMsg]             = useState("");
  const [selectedSensor, setSelectedSensor]     = useState(null);
  const [selectedFields, setSelectedFields]     = useState([]);
  const [selectedInterval, setSelectedInterval] = useState("");
  const [editingConnection, setEditingConnection] = useState(null);
  const [form, setForm] = useState({ sensorName: "", location: "", topicName: "", quantity: "", unit: "" });
  const [errors, setErrors] = useState({});

  // Restore panel state
  const [showRestorePanel, setShowRestorePanel]   = useState(false);
  const [deletedConnections, setDeletedConnections] = useState([]);
  const [deletedSensors, setDeletedSensors]       = useState([]);
  const [restoreLoading, setRestoreLoading]       = useState(false);
  const [restoringId, setRestoringId]             = useState(null); // tracks which item is restoring

  // ── Core helpers ────────────────────────────────────────────────────────────

  /**
   * fetchSensors: always takes an explicit connId so it's not dependent
   * on state that may not have updated yet.
   */
  const fetchSensors = useCallback(async (connId) => {
    if (!connId) { setSensors([]); return; }
    try {
      const data = await getActiveSensors(connId);
      if (Array.isArray(data)) setSensors(data.map(s => ({ ...s, id: s.sensorId })));
      else setSensors([]);
    } catch {
      setSensors([]);
    }
  }, []);

  /**
   * syncConnections: fetches the full connection list from the API,
   * updates state + localStorage, and returns the mapped array so
   * callers can chain off it immediately (no need to wait for re-render).
   */
  const syncConnections = useCallback(async () => {
    try {
      const live   = await getConnections();
      const mapped = live.map(c => ({
        id:            c.connectionId,
        name:          c.connectionName,
        connectionUrl: c.connectionUrl,
        port:          c.port,
        tlsEnabled:    c.tlsEnabled,
        isPublic:      c.isPublic,
      }));
      localStorage.setItem("sb_connections", JSON.stringify(mapped));
      setConnections(mapped);
      return mapped;             // ← return so callers can use it immediately
    } catch {
      setConnections([]);
      return [];
    }
  }, []);

  // Initial load
  useEffect(() => {
    syncConnections().then(mapped => {
      if (mapped.length) {
        setActiveConnectionId(mapped[0].id);
        fetchSensors(mapped[0].id);
      }
    });
  }, [syncConnections, fetchSensors]);

  // Re-fetch sensors whenever active connection tab changes
  useEffect(() => {
    fetchSensors(activeConnectionId);
  }, [activeConnectionId, fetchSensors]);

  // ── Restore panel ───────────────────────────────────────────────────────────

  const openRestorePanel = async () => {
    setShowRestorePanel(true);
    setRestoreLoading(true);
    try {
      const [dc, ds] = await Promise.all([
        api.get("/api/Connections/deleted").then(r => r.data),
        api.get("/api/Sensors/deleted").then(r => r.data),
      ]);
      setDeletedConnections(Array.isArray(dc) ? dc : []);
      setDeletedSensors(Array.isArray(ds) ? ds : []);
    } catch {
      setDeletedConnections([]);
      setDeletedSensors([]);
    } finally {
      setRestoreLoading(false);
    }
  };

  /**
   * handleRestoreConnection
   * ─────────────────────────
   * 1. Call the restore API
   * 2. Remove it from the deleted list in the panel
   * 3. syncConnections() → get the fresh list back (no waiting for re-render)
   * 4. Set the restored connection as active using the returned list directly
   * 5. fetchSensors() with that connection's id immediately
   */
  const handleRestoreConnection = async (id) => {
    setRestoringId(id);
    try {
      await api.patch(`/api/Connections/${id}/restore`);

      // Remove from panel list — cast both sides to String to avoid number/string mismatch
      setDeletedConnections(prev =>
        prev.filter(c => String(c.connectionId ?? c.id) !== String(id))
      );

      // Sync + activate + load sensors — all in one sequential chain
      const mapped = await syncConnections();
      const restoredConn = mapped.find(c => c.id === id) ?? mapped[0];
      if (restoredConn) {
        setActiveConnectionId(restoredConn.id);
        await fetchSensors(restoredConn.id);  // explicit id — no state race
      }

      showSuccess("Connection restored and loaded successfully!");
    } catch (err) {
      console.error("Restore connection failed:", err);
      showSuccess("Failed to restore connection.", "danger");
    } finally {
      setRestoringId(null);
    }
  };

  /**
   * handleRestoreSensor
   * ─────────────────────
   * 1. Call the restore API
   * 2. Remove from panel list
   * 3. syncConnections() — backend may have also restored a parent connection
   * 4. Make sure the sensor's parent connection is active and loaded
   * 5. Re-fetch sensors for the active connection
   */
  const handleRestoreSensor = async (id, parentConnectionId) => {
    setRestoringId(id);
    try {
      await api.patch(`/api/Sensors/${id}/restore`);

      // Remove from panel list — cast both sides to String to avoid number/string mismatch
      setDeletedSensors(prev =>
        prev.filter(s => String(s.sensorId ?? s.id) !== String(id))
      );

      // Always re-sync connections — backend might have auto-restored a parent
      const mapped = await syncConnections();

      // Determine which connection to show: prefer the sensor's own connection,
      // fall back to currently active, fall back to first in list
      const targetConnId = parentConnectionId
        ?? activeConnectionId
        ?? mapped[0]?.id;

      if (targetConnId) {
        setActiveConnectionId(targetConnId);
        await fetchSensors(targetConnId);  // immediate — no state race
      }

      showSuccess("Sensor restored successfully!");
    } catch (err) {
      console.error("Restore sensor failed:", err);
      showSuccess("Failed to restore sensor.", "danger");
    } finally {
      setRestoringId(null);
    }
  };

  // ── Toast helper ────────────────────────────────────────────────────────────
  const showSuccess = (msg, type = "success") => {
    setSuccessMsg({ msg, type });
    setTimeout(() => setSuccessMsg(""), 3500);
  };

  // ── Existing handlers ────────────────────────────────────────────────────────

  const handleConnectionSaved = async (newConnection) => {
    setShowConnectionModal(false);
    const mapped = await syncConnections();
    const saved  = mapped.find(c => c.id === newConnection.id) ?? mapped[0];
    if (saved) {
      setActiveConnectionId(saved.id);
      await fetchSensors(saved.id);
    }
  };

  const handleDeleteConnection = async (connId) => {
    if (!window.confirm("Delete this connection?")) return;
    try {
      await deleteConnection(connId);
      const updated = connections.filter(c => c.id !== connId);
      setConnections(updated);
      localStorage.setItem("sb_connections", JSON.stringify(updated));
      if (activeConnectionId === connId) {
        const next = updated.length ? updated[0].id : null;
        setActiveConnectionId(next);
        await fetchSensors(next);
      }
    } catch (err) {
      console.error("Failed to delete connection:", err);
    }
  };

  const handleUpdateConnection = async (updatedData) => {
    try {
      await updateConnection(editingConnection.id, updatedData);
      const updated = connections.map(c =>
        c.id === editingConnection.id ? { ...c, name: updatedData.connectionName } : c
      );
      setConnections(updated);
      localStorage.setItem("sb_connections", JSON.stringify(updated));
      setEditingConnection(null);
    } catch (err) {
      console.error("Failed to update connection:", err);
    }
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
  };

  const validate = () => {
    const errs = {};
    if (!form.sensorName.trim()) errs.sensorName = "Required";
    if (!form.location.trim())   errs.location   = "Required";
    if (!form.topicName.trim())  errs.topicName  = "Required";
    if (!form.quantity.trim())   errs.quantity   = "Required";
    if (!form.unit.trim())       errs.unit       = "Required";
    return errs;
  };

  const handleAddSensor = async () => {
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    try {
      const res = await addSensor({ connectionId: activeConnectionId, ...form });
      if (res?.sensorId || res?.message) {
        setSensors(prev => [...prev, { id: res.sensorId || Date.now(), ...form, createdAt: new Date() }]);
        setForm({ sensorName: "", location: "", topicName: "", quantity: "", unit: "" });
        setShowForm(false);
        showSuccess("Sensor added!");
      }
    } catch (err) {
      setErrors({ sensorName: err.response?.data?.message || "Failed to add sensor." });
    }
  };

  const handleDeleteSensor = async (sensorId) => {
    if (!window.confirm("Are you sure you want to delete this sensor?")) return;
    try {
      await deleteSensor(sensorId);
      setSensors(prev => prev.filter(s => s.id !== sensorId));
    } catch (err) {
      console.error("Failed to delete sensor:", err);
    }
  };

  const toggleField  = (field) => setSelectedFields(prev =>
    prev.includes(field) ? prev.filter(f => f !== field) : [...prev, field]
  );
  const activeConn = connections.find(c => c.id === activeConnectionId);

  return (
    <div>
      {/* ── Page Header ── */}
      <div className="sb-page-header px-4 py-3 mb-4">
        <div className="d-flex justify-content-between align-items-center">
          <div>
            <h5 className="sb-header-title mb-1"><i className="bi bi-broadcast me-2 sb-accent"></i>Sensors</h5>
            <p className="sb-header-subtitle mb-0">Manage and monitor your sensors.</p>
          </div>
          {isAdmin && (
            <button
              className="btn btn-outline-warning d-flex align-items-center gap-2"
              style={{ borderRadius: "50px", padding: "7px 18px", fontWeight: 600, fontSize: "0.85rem" }}
              onClick={openRestorePanel}
            >
              <i className="bi bi-arrow-counterclockwise"></i>Restore Deleted
            </button>
          )}
        </div>
      </div>

      {/* ── Toast ── */}
      {successMsg && (
        <div className="position-fixed top-0 end-0 m-4" style={{ zIndex: 9999 }}>
          <div className={`alert alert-${successMsg.type ?? "success"} shadow border-0 d-flex align-items-center gap-2`}>
            <i className={`bi bi-${(successMsg.type ?? "success") === "success" ? "check-circle-fill" : "exclamation-circle-fill"}`}></i>
            {successMsg.msg ?? successMsg}
          </div>
        </div>
      )}

      <div className="container-fluid px-4">
        {/* Top bar */}
        <div className="d-flex justify-content-between align-items-center mb-4 flex-wrap gap-3">

          {/* Connection tabs */}
          <div className="d-flex gap-2 flex-wrap">
            {connections.length === 0 ? (
              <p className="mb-0 small" style={{ color: "var(--sb-muted)" }}>No connections yet. Add one to get started.</p>
            ) : (
              connections.map(conn => (
                <div key={conn.id} className="d-flex align-items-center position-relative me-2">
                  <button
                    className={`btn ${activeConnectionId === conn.id ? "sb-connect-btn" : "btn-outline-secondary"}`}
                    style={{ borderRadius: "50px", padding: isAdmin ? "6px 40px 6px 16px" : "6px 16px", fontWeight: 600 }}
                    onClick={() => setActiveConnectionId(conn.id)}
                  >
                    <i className="bi bi-hdd-network me-1"></i>{conn.name}
                  </button>
                  {isAdmin && (
                    <div className="dropdown position-absolute" style={{ right: "10px" }}>
                      <button
                        className="btn btn-sm p-0 border-0 bg-transparent d-flex align-items-center justify-content-center"
                        style={{ color: activeConnectionId === conn.id ? "white" : "var(--sb-muted)", width: "20px", height: "20px" }}
                        data-bs-toggle="dropdown"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <i className="bi bi-three-dots-vertical" style={{ fontSize: "0.8rem" }}></i>
                      </button>
                      <ul className="dropdown-menu dropdown-menu-end shadow border-0 py-1"
                        style={{ borderRadius: "10px", minWidth: "130px", fontSize: "0.88rem" }}>
                        <li>
                          <button className="dropdown-item d-flex align-items-center gap-2 py-2"
                            onClick={() => setEditingConnection(conn)}>
                            <i className="bi bi-pencil" style={{ color: "var(--sb-accent)" }}></i>Edit
                          </button>
                        </li>
                        <li><hr className="dropdown-divider my-1" /></li>
                        <li>
                          <button className="dropdown-item d-flex align-items-center gap-2 py-2 text-danger"
                            onClick={() => handleDeleteConnection(conn.id)}>
                            <i className="bi bi-trash"></i>Delete
                          </button>
                        </li>
                      </ul>
                    </div>
                  )}
                </div>
              ))
            )}
          </div>

          {/* Action buttons */}
          <div className="d-flex gap-2">
            <button
              className="btn btn-outline-secondary d-flex align-items-center gap-2"
              style={{ borderRadius: "50px", padding: "8px 20px", fontWeight: 600 }}
              onClick={() => setShowConnectionModal(true)}
            >
              <i className="bi bi-hdd-network"></i>Add Connection
            </button>
            <button
              className="btn sb-connect-btn d-flex align-items-center gap-2"
              style={{ borderRadius: "50px", padding: "8px 20px", fontWeight: 600 }}
              disabled={!activeConnectionId}
              onClick={() => {
                setForm({ sensorName: "", location: "", topicName: "", quantity: "", unit: "" });
                setShowForm(true);
              }}
            >
              <i className="bi bi-plus-circle-fill"></i>Add Sensor
            </button>
          </div>
        </div>

        {activeConn && (
          <p className="mb-3 small" style={{ color: "var(--sb-muted)" }}>
            <i className="bi bi-hdd-network me-1"></i>
            Showing sensors for: <strong style={{ color: "var(--sb-text)" }}>{activeConn.name}</strong>
          </p>
        )}

        {/* Sensor cards */}
        {sensors.length === 0 ? (
          <div className="text-center py-5">
            <i className="bi bi-broadcast" style={{ fontSize: "3rem", color: "var(--sb-accent)" }}></i>
            <p className="mt-3" style={{ color: "var(--sb-muted)" }}>
              {activeConnectionId ? "No sensors for this connection. Click + to add one." : "Select or add a connection first."}
            </p>
          </div>
        ) : (
          <div className="row g-3">
            {sensors.map((sensor) => (
              <div className="col-12 col-md-6 col-lg-4" key={sensor.id}>
                <div className="card border-0 shadow-sm p-3" style={{ borderRadius: "12px", backgroundColor: "var(--sb-card-bg)" }}>
                  <div className="d-flex align-items-center justify-content-between mb-2">
                    <h6 className="sb-header-title mb-0">{sensor.sensorName}</h6>
                    <span className="badge" style={{ backgroundColor: "#e8faf8", color: "var(--sb-accent)", border: "1px solid var(--sb-accent)", borderRadius: "20px" }}>
                      <span className="sb-pulse-dot me-1"></span>Active
                    </span>
                  </div>
                  <p style={{ color: "var(--sb-muted)", fontSize: "0.85rem" }} className="mb-1">
                    <i className="bi bi-geo-alt me-1"></i>{sensor.location || sensor.locatedAt}
                  </p>
                  <p style={{ color: "var(--sb-muted)", fontSize: "0.85rem" }} className="mb-1">
                    <i className="bi bi-tag me-1"></i>{sensor.topicName}
                  </p>
                  {sensor.quantity && (
                    <p style={{ color: "var(--sb-muted)", fontSize: "0.85rem" }} className="mb-0">
                      <i className="bi bi-rulers me-1"></i>{sensor.quantity} ({sensor.unit})
                    </p>
                  )}
                  <p style={{ color: "var(--sb-muted)", fontSize: "0.85rem" }} className="mt-2 mb-0">
                    <i className="bi bi-calendar me-1"></i>
                    Added: {sensor.createdAt ? new Date(sensor.createdAt).toLocaleDateString() : ""}
                  </p>
                  <div className="mt-3 pt-2 d-flex justify-content-between align-items-center"
                    style={{ borderTop: "1px solid var(--sb-border)" }}>
                    <span
                      style={{ cursor: "pointer", color: "var(--sb-accent)", fontSize: "0.9rem" }}
                      onClick={() => { setSelectedSensor(sensor); setSelectedFields([]); setSelectedInterval(""); }}
                    >
                      <i className="bi bi-sliders me-1"></i>Configure & View Data
                    </span>
                    {isAdmin && (
                      <span
                        style={{ cursor: "pointer", color: "#dc3545", fontSize: "0.9rem" }}
                        onClick={() => handleDeleteSensor(sensor.id)}
                      >
                        <i className="bi bi-trash me-1"></i>Delete
                      </span>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* ── Restore Panel Modal ── */}
      {showRestorePanel && (
        <div
          className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center"
          style={{ backgroundColor: "rgba(0,0,0,0.55)", zIndex: 1070 }}
        >
          <div
            className="card border-0 shadow-lg p-4"
            style={{ width: "580px", maxHeight: "80vh", overflowY: "auto", borderRadius: "18px", backgroundColor: "var(--sb-white)" }}
          >
            <div className="d-flex justify-content-between align-items-center mb-4">
              <h5 className="mb-0">
                <i className="bi bi-arrow-counterclockwise me-2" style={{ color: "var(--sb-accent)" }}></i>
                Restore Deleted Items
              </h5>
              <button className="btn-close" onClick={() => setShowRestorePanel(false)}></button>
            </div>

            {restoreLoading ? (
              <div className="text-center py-4">
                <div className="spinner-border" style={{ color: "var(--sb-accent)" }}></div>
                <p className="mt-2 small" style={{ color: "var(--sb-muted)" }}>Loading deleted items…</p>
              </div>
            ) : (
              <>
                {/* ── Deleted Connections ── */}
                <h6 className="mb-3" style={{ color: "var(--sb-text)", fontWeight: 700 }}>
                  <i className="bi bi-hdd-network me-2" style={{ color: "var(--sb-accent)" }}></i>
                  Deleted Connections ({deletedConnections.length})
                </h6>

                {deletedConnections.length === 0 ? (
                  <p className="small mb-4" style={{ color: "var(--sb-muted)" }}>No deleted connections.</p>
                ) : (
                  <div className="mb-4">
                    {deletedConnections.map(c => {
                      const id = c.connectionId ?? c.id;
                      const isRestoring = String(restoringId) === String(id);
                      return (
                        <div
                          key={id}
                          className="d-flex justify-content-between align-items-center p-2 mb-2"
                          style={{ background: "var(--sb-light-bg)", borderRadius: "10px", opacity: isRestoring ? 0.65 : 1, transition: "opacity 0.2s" }}
                        >
                          <div>
                            <p className="mb-0 fw-semibold" style={{ fontSize: "0.88rem", color: "var(--sb-text)" }}>
                              {c.connectionName ?? c.name}
                            </p>
                            <p className="mb-0 small" style={{ color: "var(--sb-muted)" }}>{c.connectionUrl}</p>
                          </div>
                          <button
                            className="btn btn-sm btn-outline-success d-flex align-items-center gap-1"
                            style={{ borderRadius: "20px", fontSize: "0.78rem", minWidth: 80 }}
                            disabled={!!restoringId}
                            onClick={() => handleRestoreConnection(id)}
                          >
                            {isRestoring
                              ? <><span className="spinner-border spinner-border-sm" style={{ width: "0.75rem", height: "0.75rem" }}></span> Restoring…</>
                              : <><i className="bi bi-arrow-counterclockwise"></i> Restore</>
                            }
                          </button>
                        </div>
                      );
                    })}
                  </div>
                )}

                <hr />

                {/* ── Deleted Sensors ── */}
                <h6 className="mb-3 mt-3" style={{ color: "var(--sb-text)", fontWeight: 700 }}>
                  <i className="bi bi-broadcast me-2" style={{ color: "var(--sb-accent)" }}></i>
                  Deleted Sensors ({deletedSensors.length})
                </h6>

                {deletedSensors.length === 0 ? (
                  <p className="small" style={{ color: "var(--sb-muted)" }}>No deleted sensors.</p>
                ) : (
                  deletedSensors.map(s => {
                    const id           = s.sensorId ?? s.id;
                    // Capture the sensor's own connectionId so we can switch to
                    // the right tab after restoring (even if it was also restored)
                    const parentConnId = s.connectionId ?? s.connection_id ?? null;
                    const isRestoring  = String(restoringId) === String(id);
                    return (
                      <div
                        key={id}
                        className="d-flex justify-content-between align-items-center p-2 mb-2"
                        style={{ background: "var(--sb-light-bg)", borderRadius: "10px", opacity: isRestoring ? 0.65 : 1, transition: "opacity 0.2s" }}
                      >
                        <div>
                          <p className="mb-0 fw-semibold" style={{ fontSize: "0.88rem", color: "var(--sb-text)" }}>
                            {s.sensorName ?? s.name}
                          </p>
                          <p className="mb-0 small" style={{ color: "var(--sb-muted)" }}>
                            {s.location ?? s.locatedAt} · {s.topicName}
                          </p>
                        </div>
                        <button
                          className="btn btn-sm btn-outline-success d-flex align-items-center gap-1"
                          style={{ borderRadius: "20px", fontSize: "0.78rem", minWidth: 80 }}
                          disabled={!!restoringId}
                          onClick={() => handleRestoreSensor(id, parentConnId)}
                        >
                          {isRestoring
                            ? <><span className="spinner-border spinner-border-sm" style={{ width: "0.75rem", height: "0.75rem" }}></span> Restoring…</>
                            : <><i className="bi bi-arrow-counterclockwise"></i> Restore</>
                          }
                        </button>
                      </div>
                    );
                  })
                )}
              </>
            )}
          </div>
        </div>
      )}

      {/* Connection Modal */}
      {showConnectionModal && (
        <ConnectionModal onClose={() => setShowConnectionModal(false)} onSave={handleConnectionSaved} />
      )}

      {/* Edit Connection Modal */}
      {editingConnection && (
        <MqttForm
          onClose={() => setEditingConnection(null)}
          initialData={{
            connectionName: editingConnection.name,
            connectionUrl:  editingConnection.connectionUrl || "",
            port:           editingConnection.port || "1883",
            username:       editingConnection.username || "",
            password:       editingConnection.password || "",
            tlsEnabled:     editingConnection.tlsEnabled || false,
            isPublic:       editingConnection.isPublic || false,
          }}
          onConnected={(updatedData) => handleUpdateConnection(updatedData)}
          isEditing={true}
        />
      )}

      {/* Add Sensor Form */}
      {showForm && (
        <div
          className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center"
          style={{ backgroundColor: "rgba(0,0,0,0.5)", zIndex: 1050 }}
        >
          <div className="card border-0 shadow-lg p-4" style={{ width: "500px", borderRadius: "20px", backgroundColor: "var(--sb-white)" }}>
            <div className="d-flex justify-content-between mb-4">
              <h5 className="mb-0"><i className="bi bi-broadcast me-2" style={{ color: "var(--sb-accent)" }}></i>Add New Sensor</h5>
              <button className="btn-close" onClick={() => { setShowForm(false); setErrors({}); }}></button>
            </div>
            {[
              { label: "Sensor Name", name: "sensorName", placeholder: "e.g. Temperature Sensor 1" },
              { label: "Location",    name: "location",   placeholder: "e.g. Factory Floor A" },
              { label: "Topic Name",  name: "topicName",  placeholder: "e.g. sensors/temperature/1" },
            ].map(({ label, name, placeholder }) => (
              <div className="mb-3" key={name}>
                <label className="form-label sb-form-label">{label} <span className="text-danger">*</span></label>
                <input
                  type="text" name={name}
                  className={`form-control sb-input ${errors[name] ? "is-invalid" : ""}`}
                  placeholder={placeholder} value={form[name]} onChange={handleChange}
                />
                {errors[name] && <div className="invalid-feedback">{errors[name]}</div>}
              </div>
            ))}
            <div className="mb-4">
              <label className="form-label sb-form-label">Data Fields <span className="text-danger">*</span></label>
              <div className="d-flex gap-3">
                <div className="flex-fill">
                  <input type="text" name="quantity"
                    className={`form-control sb-input ${errors.quantity ? "is-invalid" : ""}`}
                    placeholder="Quantity (e.g. Temperature)" value={form.quantity} onChange={handleChange} />
                  {errors.quantity && <div className="invalid-feedback">{errors.quantity}</div>}
                </div>
                <div className="flex-fill">
                  <input type="text" name="unit"
                    className={`form-control sb-input ${errors.unit ? "is-invalid" : ""}`}
                    placeholder="Unit (e.g. °C)" value={form.unit} onChange={handleChange} />
                  {errors.unit && <div className="invalid-feedback">{errors.unit}</div>}
                </div>
              </div>
            </div>
            <div className="d-flex gap-2 justify-content-end">
              <button className="btn btn-outline-secondary" onClick={() => { setShowForm(false); setErrors({}); }}>Cancel</button>
              <button className="btn sb-connect-btn" onClick={handleAddSensor}>
                <i className="bi bi-plus-circle me-2"></i>Add Sensor
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Sensor Detail Popup */}
      {selectedSensor && (
        <div
          className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center"
          style={{ backgroundColor: "rgba(0,0,0,0.6)", zIndex: 1060 }}
        >
          <div className="card border-0 shadow-lg p-4"
            style={{ width: "500px", borderRadius: "16px", backgroundColor: "var(--sb-white)", maxHeight: "90vh", overflowY: "auto" }}>
            <div className="d-flex justify-content-between mb-3">
              <h5 className="mb-0">
                <i className="bi bi-broadcast me-2" style={{ color: "var(--sb-accent)" }}></i>
                {selectedSensor.sensorName}
              </h5>
              <button className="btn-close" onClick={() => setSelectedSensor(null)}></button>
            </div>
            <div className="mb-3 p-3" style={{ backgroundColor: "var(--sb-light-bg)", borderRadius: "10px" }}>
              <p className="sb-form-label mb-1"><i className="bi bi-geo-alt me-1"></i>Location: {selectedSensor.location || selectedSensor.locatedAt}</p>
              <p className="sb-form-label mb-1"><i className="bi bi-tag me-1"></i>Topic: {selectedSensor.topicName}</p>
              {selectedSensor.quantity && (
                <p className="sb-form-label mb-0"><i className="bi bi-rulers me-1"></i>{selectedSensor.quantity} ({selectedSensor.unit})</p>
              )}
            </div>
            <div className="mb-3">
              <label className="sb-form-label mb-2">Select Data Fields</label>
              {selectedSensor.quantity ? (
                <div
                  className="d-flex align-items-center justify-content-between p-2"
                  style={{ backgroundColor: "var(--sb-light-bg)", borderRadius: "8px", cursor: "pointer" }}
                  onClick={() => toggleField(selectedSensor.quantity)}
                >
                  <span style={{ fontSize: "0.88rem" }}>{selectedSensor.quantity} ({selectedSensor.unit})</span>
                  <input
                    type="checkbox"
                    checked={selectedFields.includes(selectedSensor.quantity)}
                    onChange={() => toggleField(selectedSensor.quantity)}
                    style={{ accentColor: "var(--sb-accent)", width: "16px", height: "16px" }}
                  />
                </div>
              ) : (
                <p className="small" style={{ color: "var(--sb-muted)" }}>No data fields specified.</p>
              )}
            </div>
            <div className="mb-4">
              <label className="sb-form-label mb-2">Select Time Interval</label>
              <select className="form-select sb-input" value={selectedInterval} onChange={(e) => setSelectedInterval(e.target.value)}>
                <option value="">-- Select Interval --</option>
                {["1 Week","15 Days","1 Month","3 Months"].map(i => <option key={i} value={i}>{i}</option>)}
              </select>
            </div>
            <div className="d-flex justify-content-end">
              <button
                className="btn sb-connect-btn"
                disabled={!selectedFields.length || !selectedInterval}
                onClick={() => {
                  setSelectedSensor(null);
                  navigate("/dashboard", {
                    state: {
                      sensorId:   selectedSensor.sensorId,
                      sensorName: selectedSensor.sensorName,
                      interval:   selectedInterval,
                      unit:       selectedSensor.unit,
                    },
                  });
                }}
              >
                <i className="bi bi-speedometer2 me-2"></i>View
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sensor;
